stabilizers = [s.strip() for s in stabilizers_str.split(',') if s.strip()]

# Write to file for reference (optional but good for debugging)
with open('target_stabilizers.txt', 'w') as f:
    for s in stabilizers:
        f.write(s + '\n')

print(f"Loaded {len(stabilizers)} stabilizers.")

# Load baseline
with open('baseline.stim', 'r') as f:
    baseline_text = f.read()

baseline = stim.Circuit(baseline_text)
print("Baseline loaded.")

# Try graph state synthesis
try:
    print("Synthesizing...")
    # Tableau.from_stabilizers
    t = stim.Tableau.from_stabilizers([stim.PauliString(s) for s in stabilizers], allow_underconstrained=True, allow_redundant=True)
    
    # Synthesize
    circuit = t.to_circuit(method="graph_state")
    
    # Check metrics (simple check)
    # count CX
    cx_count = 0
    for instr in circuit:
        if instr.name == "CX" or instr.name == "CNOT":
             cx_count += len(instr.targets_copy()) // 2
    
    print(f"Candidate generated. CX count: {cx_count}")
    
    with open('candidate.stim', 'w') as f:
        f.write(str(circuit))
        
    print("Candidate written to candidate.stim")
    
except Exception as e:
    print(f"Error synthesizing: {e}")

